"use client"

import { useState } from "react"
import { Card, CardContent } from "@/components/ui/card"
import { Input } from "@/components/ui/input"
import { Badge } from "@/components/ui/badge"
import { Button } from "@/components/ui/button"
import { Search, Mail, Phone } from "lucide-react"
import { LocalDB } from "@/lib/local-storage/db"
import { Select, SelectTrigger, SelectValue, SelectContent, SelectItem } from "@/components/ui/select"
import { useToast } from "@/components/ui/toast"

interface User {
  id: string
  full_name: string
  email: string
  role: string
  phone: string | null
  created_at: string
}

interface UserManagementTableProps {
  users: User[]
  onDelete?: (id: string) => Promise<void> | void
  onToggleRole?: (id: string) => Promise<void> | void
}

export function UserManagementTable({ users, onDelete, onToggleRole }: UserManagementTableProps) {
  const [searchTerm, setSearchTerm] = useState("")

  const filteredUsers = users.filter(
    (user) =>
      user.full_name.toLowerCase().includes(searchTerm.toLowerCase()) ||
      user.email.toLowerCase().includes(searchTerm.toLowerCase()),
  )

  // Local add user form state
  const [newName, setNewName] = useState("")
  const [newEmail, setNewEmail] = useState("")
  const [newPassword, setNewPassword] = useState("")
  const [newRole, setNewRole] = useState("investor")
  const [creating, setCreating] = useState(false)
  const [togglingId, setTogglingId] = useState<string | null>(null)
  const [deletingId, setDeletingId] = useState<string | null>(null)
  const { toast } = useToast()

  const createUser = async () => {
    try {
      if (!newEmail || !newPassword || !newName) return toast({ title: "Missing fields", description: "Please fill name, email and password" })
      setCreating(true)
      await LocalDB.createUser(newEmail, newPassword, newName, newRole as any)
      toast({ title: "User created", description: `${newName} was added.` })
      // reset form
      setNewName("")
      setNewEmail("")
      setNewPassword("")
      setNewRole("investor")
      // reload to pick up user in parent lists
      setTimeout(() => window.location.reload(), 300)
    } catch (e: any) {
      toast({ title: "Create failed", description: e?.message || "Failed to create user" })
    } finally {
      setCreating(false)
    }
  }

  const getRoleBadgeColor = (role: string) => {
    switch (role) {
      case "admin":
        return "bg-purple-100 text-purple-800"
      case "portfolio_manager":
        return "bg-blue-100 text-blue-800"
      case "investor":
        return "bg-green-100 text-green-800"
      default:
        return "bg-gray-100 text-gray-800"
    }
  }

  const formatDate = (date: string) => {
    return new Date(date).toLocaleDateString("en-IN", {
      year: "numeric",
      month: "short",
      day: "numeric",
    })
  }

  return (
    <div className="space-y-6">
      <Card>
        <CardContent className="pt-6">
          <div className="grid gap-3 md:grid-cols-3">
            <div className="relative md:col-span-2">
              <Search className="absolute left-3 top-1/2 h-4 w-4 -translate-y-1/2 text-gray-400" />
              <Input
                placeholder="Search users by name or email..."
                className="pl-10"
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
              />
            </div>

            <div className="md:col-span-1 flex items-center gap-2">
              <Input placeholder="Name" value={newName} onChange={(e) => setNewName(e.target.value)} />
              <Input placeholder="Email" value={newEmail} onChange={(e) => setNewEmail(e.target.value)} />
              <Input placeholder="Password" value={newPassword} onChange={(e) => setNewPassword(e.target.value)} />
              <Select value={newRole} onValueChange={(v) => setNewRole(v)} className="w-36">
                <SelectTrigger>
                  <SelectValue />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="investor">Investor</SelectItem>
                  <SelectItem value="portfolio_manager">Manager</SelectItem>
                  <SelectItem value="admin">Admin</SelectItem>
                </SelectContent>
              </Select>
              <Button onClick={createUser} disabled={creating}>{creating ? "Adding..." : "Add"}</Button>
            </div>
          </div>
        </CardContent>
      </Card>

      <Card>
        <CardContent className="p-0">
          <div className="overflow-x-auto">
            <table className="w-full">
              <thead className="border-b bg-gray-50">
                <tr>
                  <th className="p-4 text-left text-sm font-semibold text-gray-900">Name</th>
                  <th className="p-4 text-left text-sm font-semibold text-gray-900">Email</th>
                  <th className="p-4 text-left text-sm font-semibold text-gray-900">Role</th>
                  <th className="p-4 text-left text-sm font-semibold text-gray-900">Phone</th>
                  <th className="p-4 text-left text-sm font-semibold text-gray-900">Joined</th>
                  <th className="p-4 text-right text-sm font-semibold text-gray-900">Actions</th>
                </tr>
              </thead>
              <tbody>
                {filteredUsers.map((user) => (
                  <tr key={user.id} className="border-b hover:bg-gray-50">
                    <td className="p-4 font-medium text-gray-900">{user.full_name}</td>
                    <td className="p-4">
                      <div className="flex items-center gap-2 text-sm text-gray-600">
                        <Mail className="h-4 w-4" />
                        {user.email}
                      </div>
                    </td>
                    <td className="p-4">
                      <Badge className={getRoleBadgeColor(user.role)}>{user.role.replace("_", " ")}</Badge>
                    </td>
                    <td className="p-4">
                      {user.phone ? (
                        <div className="flex items-center gap-2 text-sm text-gray-600">
                          <Phone className="h-4 w-4" />
                          {user.phone}
                        </div>
                      ) : (
                        <span className="text-sm text-gray-400">-</span>
                      )}
                    </td>
                    <td className="p-4 text-sm text-gray-600">{formatDate(user.created_at)}</td>
                    <td className="p-4 text-right flex justify-end gap-2">
                      <Button
                        variant="outline"
                        size="sm"
                        disabled={togglingId === user.id}
                        onClick={async () => {
                          try {
                            setTogglingId(user.id)
                            if (onToggleRole) {
                              await onToggleRole(user.id)
                              toast({ title: "Role updated" })
                              setTogglingId(null)
                              return
                            }

                            // Fallback: toggle between admin and investor in localStorage
                            const users = JSON.parse(localStorage.getItem("users") || "[]") as any[]
                            const idx = users.findIndex((u) => u.id === user.id)
                            if (idx === -1) return
                            users[idx].role = users[idx].role === "admin" ? "investor" : "admin"
                            localStorage.setItem("users", JSON.stringify(users))
                            toast({ title: "Role updated" })
                            // simple page refresh to pick up change
                            setTimeout(() => window.location.reload(), 200)
                          } catch (e) {
                            console.error(e)
                            toast({ title: "Update failed", description: "Could not toggle role" })
                          } finally {
                            setTogglingId(null)
                          }
                        }}
                      >
                        Toggle Role
                      </Button>

                      <Button
                        variant="destructive"
                        size="sm"
                        disabled={deletingId === user.id}
                        onClick={async () => {
                          try {
                            setDeletingId(user.id)
                            if (onDelete) {
                              await onDelete(user.id)
                              toast({ title: "User deleted" })
                              setDeletingId(null)
                              return
                            }

                            // Fallback delete: remove from localStorage users array
                            const users = JSON.parse(localStorage.getItem("users") || "[]") as any[]
                            const filtered = users.filter((u) => u.id !== user.id)
                            localStorage.setItem("users", JSON.stringify(filtered))
                            toast({ title: "User deleted" })
                            setTimeout(() => window.location.reload(), 200)
                          } catch (e) {
                            console.error(e)
                            toast({ title: "Delete failed", description: "Could not delete user" })
                          } finally {
                            setDeletingId(null)
                          }
                        }}
                      >
                        Delete
                      </Button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </CardContent>
      </Card>

      {filteredUsers.length === 0 && (
        <Card>
          <CardContent className="py-12 text-center">
            <p className="text-gray-500">No users found matching your search.</p>
          </CardContent>
        </Card>
      )}
    </div>
  )
}
